	ID    int
	Name  string
	Price float64
}

// ListProducts queries the database for products sorted by a specific column and direction.
func ListProducts(db *sql.DB, orderBy string, sortDir string) ([]Product, error) {
	// Whitelist allowed columns to prevent SQL injection
	allowedColumns := map[string]bool{
		"id":    true,
		"name":  true,
		"price": true,
	}

	orderByLower := strings.ToLower(orderBy)
	if !allowedColumns[orderByLower] {
		return nil, fmt.Errorf("invalid orderBy column: %s", orderBy)
	}

	// Whitelist allowed sort directions
	sortDirUpper := strings.ToUpper(sortDir)
	if sortDirUpper != "ASC" && sortDirUpper != "DESC" {
		return nil, fmt.Errorf("invalid sort direction: %s", sortDir)
	}

	query := fmt.Sprintf("SELECT id, name, price FROM products ORDER BY %s %s", orderByLower, sortDirUpper)

	rows, err := db.Query(query)
	if err != nil {
		return nil, fmt.Errorf("failed to query products: %w", err)
	}
	defer rows.Close()

	var products []Product
	for rows.Next() {
		var p Product
		if err := rows.Scan(&p.ID, &p.Name, &p.Price); err != nil {
			return nil, fmt.Errorf("failed to scan product: %w", err)
		}
		products = append(products, p)
	}

	if err := rows.Err(); err != nil {
		return nil, fmt.Errorf("rows iteration error: %w", err)
	}

	return products, nil
}

