import (
	"database/sql"
	"errors"
	"strings"
)

type Product struct {
	ID    int
	Name  string
	Price float64
}

// ListProducts queries the database for products sorted by a specific column and direction.
func ListProducts(db *sql.DB, orderBy string, sortDir string) ([]Product, error) {
	// Normalize inputs
	sortDir = strings.ToUpper(sortDir)
	orderBy = strings.ToLower(orderBy)

	// Validate sortDir against whitelist
	if sortDir != "ASC" && sortDir != "DESC" {
		return nil, errors.New("invalid sort direction")
	}

	// Validate orderBy against whitelist of allowed columns
	allowedColumns := map[string]string{
		"id":    "id",
		"name":  "name",
		"price": "price",
	}

	safeOrderBy, ok := allowedColumns[orderBy]
	if !ok {
		return nil, errors.New("invalid order by column")
	}

	query := "SELECT id, name, price FROM products ORDER BY " + safeOrderBy + " " + sortDir

	rows, err := db.Query(query)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var products []Product
	for rows.Next() {
		var p Product
		err := rows.Scan(&p.ID, &p.Name, &p.Price)
		if err != nil {
			return nil, err
		}
		products = append(products, p)
	}

	if err = rows.Err(); err != nil {
		return nil, err
	}

	return products, nil
}

